export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(keyOf));
  const uniqueCandidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    for (const candidate of [cell, ...neighborsOf(cell)]) {
      uniqueCandidates.set(keyOf(candidate), candidate);
    }
  }
  return [...uniqueCandidates.values()].filter((cell) => willBeAlive(cell, liveSet));
}

